33	router.post("/register", async (req, res) => {
34	    const { recaptchaToken, ...userData } = req.body;
35	    try {
36	        if (!recaptchaToken) return res.status(400).json({ errors: ["Security token missing."] });
37	
38	        // 1. reCAPTCHA Verification
