45	        });
46	
47	        if (!googleResponse.data.success || googleResponse.data.score < 0.5) {
48	            return res.status(403).json({ errors: ["Security check failed. Please try again."] });
49	        }
50	
51	        // 2. Data Validation
52	        let validationSchema = yup.object({
53	            name: yup.string().trim().required("Full name is required"),
54	            email: yup.string().trim().email("Invalid email format").required("Email is required"),
55	            password: yup.string().trim().min(8, "Password must be at least 8 characters").required(),
56	            role: yup.string().oneOf(['FM', 'Tenant', 'Staff']).required("Role is required"),
57	            tenantCode: yup.string().required("Access code is required")
58	        });
59	
60	        let validatedData = await validationSchema.validate(userData, { abortEarly: false });
61	
62	        // --- 3. THE SECURITY GATE ---
63	
64	        // BLOCK A: Prevent anyone from registering as FM publicly
65	        if (validatedData.role === 'FM') {
66	            return res.status(403).json({ errors: ["Administrative accounts cannot be created publicly."] });
67	        }
68	
69	        // BLOCK B: Tenant Registration (One-Time Invite Check)
